module design_18(
    input clk,
    input rst_n,
    output [3:0] data_out
);
    // 设计实现: 异步复位和使能控制
    reg [3:0] counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            counter <= 0;
        else
            counter <= counter + 1;
    end

    assign data_out = counter;
endmodule
